    21→abstract class Team with _$Team {
    22→  const Team._();
    23→
    24→  @JsonSerializable(
    25→    explicitToJson: true,
    26→    fieldRename: Constants.modelFieldRename,
    27→  )
    28→  const factory Team({
    29→    @Default(null) String? id,
    30→    @Default(null) String? name,
    31→    @Default(null) String? ownerUserId,
    32→    @Default(TeamType.multiple) TeamType teamType,
    33→    @Default(null) DateTime? createdAt, // assumes UTC
    34→    @Default(null) DateTime? updatedAt, // assumes UTC
    35→    @Default(null) DateTime? teamPlanCancelAt,
    36→    @Default(null) DateTime? teamPlanDowngradeAt,
    37→    @Default(null) String? imageUrl,
    38→    @Default(null) TeamPlan? teamPlan,
    39→    @Default(null) TeamPlan? nextTeamPlan,
    40→    @Default(null) String? presignedImageUrl,
    41→    @Default(null) String? billingFailureReason,
    42→    @Default(null) String? downgradePlanId,
    43→  }) = _Team;
    44→
    45→  factory Team.fromJson(Map<String, dynamic> json) => _$TeamFromJson(json);
    46→
    47→  bool get isSingleUserTeam => teamType == TeamType.single;
    48→
    49→  // Returns the current TeamPlanStatus based on teamPlan and nextTeamPlan (フローチャート準拠)
    50→  TeamPlanStatus get teamPlanStatus {
    51→    // 1. teamPlanがnullまたはisActive!=trueの場合
    52→    if (teamPlan == null || teamPlan!.isActive != true) {
    53→      return TeamPlanStatus.noContract;
    54→    }
    55→
    56→    // 2. 期限切れか
    57→    final now = DateTime.now();
    58→    final endDate = teamPlan!.endDate;
    59→    // 以下の場合は nextTeamPlan の endDate を使用する
    60→    // 1. nextTeamPlan が存在
    61→    // 2. nextTeamPlan の isPendingActivation が true
    62→    // 3. teamPlan の endDate が nextTeamPlan の startDate と同じ (連続してプランを継続している)
    63→    final effectiveEndDate = (nextTeamPlan != null &&
    64→            nextTeamPlan!.isPendingActivation == true &&
    65→            endDate == nextTeamPlan!.startDate)
    66→        ? nextTeamPlan!.endDate
    67→        : endDate;
    68→    final isExpired =
    69→        effectiveEndDate != null && effectiveEndDate.isBefore(now);
    70→    if (isExpired) {
    71→      if (nextTeamPlan != null && nextTeamPlan!.isPendingActivation == true) {
    72→        return TeamPlanStatus.nextPlanPending;
    73→      }
    74→      return TeamPlanStatus.expired;
    75→    }
    76→
    77→    // 3. 球数制限にかかっているか
    78→    final usage = teamPlan!.currentUsage ?? 0;
    79→    final maxUsage =
    80→        (teamPlan!.plan?.maxBalls ?? 0) + (teamPlan!.extraBalls ?? 0);
    81→    if (usage >= maxUsage) {
    82→      return TeamPlanStatus.reachedLimit;
    83→    }
    84→
    85→    // 4. 警告系（30日以内, 90%到達）
    86→    if (effectiveEndDate != null) {
    87→      final oneMonthLater = now.add(const Duration(days: 30));
    88→      if (effectiveEndDate.isAfter(now) &&
    89→          effectiveEndDate.isBefore(oneMonthLater)) {
    90→        return TeamPlanStatus.expiringSoon;
    91→      }
    92→    }
    93→    if (usage >= (maxUsage * 0.9).floor()) {
    94→      return TeamPlanStatus.limitIsApproaching;
    95→    }
    96→
    97→    // 5. 問題なし
    98→    return TeamPlanStatus.ok;
    99→  }
   100→}
   101→
   102→// TeamPlanStatus enum moved from team_plan.dart
   103→enum TeamPlanStatus {
   104→  // Users cannot use the app when TeamPlanStatus is the following
   105→  noContract, // No paid plan contract found
   106→  nextPlanPending, // Next paid plan is pending activation
   107→  expired,
   108→  reachedLimit,
   109→
   110→  // Users can use the app when TeamPlanStatus is the following
   111→  limitIsApproaching,
   112→  expiringSoon,
   113→  ok,
   114→  ;
   115→
   116→  bool get canAnalyze =>
   117→      this == limitIsApproaching || this == expiringSoon || this == ok;
   118→}
   119→

